function partitionKey(topic, partition) {
  if (typeof topic !== 'string' || topic.length === 0) {
    throw new TypeError('topic must be a non-empty string');
  }
  if (!Number.isSafeInteger(partition) || partition < 0) {
    throw new TypeError('partition must be a non-negative safe integer');
  }
  return `${topic}:${partition}`;
}

function checkedOffset(offset) {
  if (!Number.isSafeInteger(offset) || offset < 0) {
    throw new TypeError('offset must be a non-negative safe integer');
  }
  return offset;
}

export class OffsetTracker {
  #committed = new Map();

  constructor(initialPositions = {}) {
    for (const [key, value] of Object.entries(initialPositions)) {
      this.#committed.set(key, checkedOffset(value));
    }
  }

  complete(topic, partition, offset) {
    const key = partitionKey(topic, partition);
    const completedOffset = checkedOffset(offset);
    const current = this.#committed.get(key) ?? -1;
    if (completedOffset > current) {
      this.#committed.set(key, completedOffset);
    }
    return this.#committed.get(key) ?? -1;
  }

  committed(topic, partition) {
    return this.#committed.get(partitionKey(topic, partition)) ?? -1;
  }

  snapshot() {
    return Object.fromEntries(
      [...this.#committed.entries()].sort(([left], [right]) =>
        left.localeCompare(right)
      )
    );
  }
}

