import test from 'node:test';
import assert from 'node:assert/strict';

import { OffsetTracker } from '../src/offset-tracker.mjs';
import { processBatch } from '../src/batch-consumer.mjs';
import { formatCommitReport } from '../src/commit-report.mjs';

test('sequential deliveries advance the stored position', () => {
  const tracker = new OffsetTracker({ 'orders:0': 9 });

  assert.equal(tracker.complete('orders', 0, 10), 10);
  assert.equal(tracker.complete('orders', 0, 11), 11);
  assert.equal(tracker.committed('orders', 0), 11);
});

test('the original consumer lane reports completed work', async () => {
  const tracker = new OffsetTracker({ 'events:0': 4 });
  const outcomes = await processBatch(
    [{ topic: 'events', partition: 0, offset: 5, value: 'ready' }],
    async (record) => record.value.toUpperCase(),
    tracker
  );

  assert.deepEqual(outcomes, [{
    topic: 'events',
    partition: 0,
    offset: 5,
    committed: 5,
    result: 'READY'
  }]);
  assert.equal(formatCommitReport(tracker.snapshot()), 'events:0@5');
});
